INSERT INTO `products` VALUES (18,'/Content/Demo/img/Productos/prod_6983c93bbb5066.46181112.webp','Ácido Hialuronico The Ordinary 30ml','Ideal para pieles secas, brinda hidratación y mejora la textura ',5,'Active',420),(19,'/Content/Demo/img/Productos/prod_6984f24ed19203.26024632.webp','Easy Bake Setting Spray 100 ml','El Easy Bake Setting Spray de Huda Beauty es un fijador de maquillaje de larga duración (16 horas) que difumina poros y controla brillos, ofreciendo un acabado mate natural, sin alcohol ni fragancia.',6,'Active',1390),(20,'/Content/Demo/img/Productos/prod_6984f30b4e7573.89010907.webp','On’Till Dawn Big & Bitty One Size ','pray fijador de maquillaje matificante en tamaño completo y de viaje: la fórmula ofrece hasta 16 horas de uso a prueba de sudor, impermeable y a prueba de transferencia, mientras aborda la grasa y el brillo.',6,'Active',1650),(21,'/Content/Demo/img/Productos/prod_6984f93adc87c5.61325526.webp','Make It Last Milani Original ','El fijador Milani Make It Last Setting Spray es un producto 3-en-1 (prepara, corrige y fija) diseñado para mantener el maquillaje impecable hasta por 16 o 24 horas',6,'Active',370),(23,'/Content/Demo/img/Productos/prod_6984f9e9a534e9.83950513.webp','GOOD GIRL Carolina Herrera ','Good Girl es una fragancia audaz y sofisticada que celebra la dualidad de la mujer moderna: elegante y atrevida a la vez. Con notas dulces y sensuales, es el equilibrio perfecto entre poder, feminidad y misterio. ',7,'Active',3080),(24,'/Content/Demo/img/Productos/prod_6984fa90da65f2.70130985.jpeg','Setting Mist Beau Visage ','El Sellador Matificante Setting Mist de Beau Visage es un spray fijador de maquillaje con un acabado mate que te ayuda a mantener tu look impecable durante todo el día.',6,'Active',250),(25,'/Content/Demo/img/Productos/prod_6984facd4df5c2.83822881.jpeg','Moschino Toy Boy','Aroma intenso y moderno, especiado y seductor, para una masculinidad audaz.',7,'Active',2320),(26,'/Content/Demo/img/Productos/prod_6984fb5183d53